    /* COACH */
    "The AI coach": { he:"מאמן ה-AI", ar:"مدرّب الذكاء الاصطناعي", ru:"ИИ-коуч", es:"El coach de IA", fr:"Le coach IA", de:"Der KI-Coach" },
    "A guide that's read": { he:"מדריך שקרא", ar:"مرشدٌ قرأ", ru:"Наставник, прочитавший", es:"Un guía que ha leído", fr:"Un guide qui a lu", de:"Ein Begleiter, der" },
    "every tradition.": { he:"כל מסורת.", ar:"كل تقليد.", ru:"каждую традицию.", es:"cada tradición.", fr:"chaque tradition.", de:"jede Tradition gelesen hat." },
    "Wise, practical, supportive, and evidence-aware. It explains your results, compares what each tradition would suggest, and turns it into habits sized for your real life.": { he:"חכם, מעשי, תומך ומודע לראיות. הוא מסביר את התוצאות שלך, משווה את מה שכל מסורת תציע, והופך זאת להרגלים בגודל המתאים לחיים האמיתיים שלך.", ar:"حكيم، عملي، داعم، وواعٍ بالأدلّة. يشرح نتائجك، ويقارن ما يقترحه كل تقليد، ويحوّله إلى عاداتٍ بحجم حياتك الحقيقية.", ru:"Мудрый, практичный, поддерживающий и опирающийся на доказательства. Он объясняет ваши результаты, сравнивает, что предложила бы каждая традиция, и превращает это в привычки под вашу реальную жизнь.", es:"Sabio, práctico, cercano y con base en la evidencia. Explica tus resultados, compara lo que sugeriría cada tradición y lo convierte en hábitos a la medida de tu vida real.", fr:"Sage, pratique, bienveillant et fondé sur les preuves. Il explique vos résultats, compare ce que suggérerait chaque tradition et le transforme en habitudes à la taille de votre vraie vie.", de:"Weise, praktisch, unterstützend und evidenzbewusst. Er erklärt Ihre Ergebnisse, vergleicht, was jede Tradition empfehlen würde, und macht daraus Gewohnheiten im Maß Ihres echten Lebens." },
    "Explains results": { he:"מסביר תוצאות", ar:"يشرح النتائج", ru:"Объясняет результаты", es:"Explica resultados", fr:"Explique les résultats", de:"Erklärt Ergebnisse" },
    "Compares traditions": { he:"משווה מסורות", ar:"يقارن التقاليد", ru:"Сравнивает традиции", es:"Compara tradiciones", fr:"Compare les traditions", de:"Vergleicht Traditionen" },
    "Builds habits": { he:"בונה הרגלים", ar:"يبني العادات", ru:"Формирует привычки", es:"Crea hábitos", fr:"Crée des habitudes", de:"Baut Gewohnheiten auf" },
    "Plans your week": { he:"מתכנן את השבוע שלך", ar:"يخطّط أسبوعك", ru:"Планирует вашу неделю", es:"Planifica tu semana", fr:"Planifie votre semaine", de:"Plant Ihre Woche" },
    "My energy keeps crashing at 3pm. What do I do?": { he:"האנרגיה שלי צונחת כל יום בשלוש אחר הצהריים. מה לעשות?", ar:"طاقتي تنهار كل يوم عند الثالثة عصرًا. ماذا أفعل؟", ru:"У меня каждый день в три часа дня падает энергия. Что делать?", es:"Mi energía se desploma a las 3 de la tarde. ¿Qué hago?", fr:"Mon énergie s'effondre chaque jour à 15 h. Que faire ?", de:"Meine Energie sackt jeden Tag um 15 Uhr ab. Was tun?" },
    "Holos · integrative coach": { he:"הולוס · מאמן אינטגרטיבי", ar:"هولوس · مدرّب تكاملي", ru:"Holos · интегративный коуч", es:"Holos · coach integrativo", fr:"Holos · coach intégratif", de:"Holos · integrativer Coach" },
    "One small ritual": { he:"טקס קטן אחד", ar:"طقسٌ صغيرٌ واحد", ru:"Один маленький ритуал", es:"Un pequeño ritual", fr:"Un petit rituel", de:"Ein kleines Ritual" },

