    "that felt human.": { he:"שהרגישה אנושית.", ar:"يبدو إنسانيًّا.", ru:"которое ощущается человечным.", es:"que se sintió humana.", fr:"qui semblait humaine.", de:"die sich menschlich anfühlte." },

    /* SCIENCE */
    "Scientific foundation": { he:"בסיס מדעי", ar:"أساس علمي", ru:"Научная основа", es:"Fundamento científico", fr:"Fondement scientifique", de:"Wissenschaftliche Grundlage" },
    "Ancient lenses.": { he:"עדשות עתיקות.", ar:"عدساتٌ قديمة.", ru:"Древние линзы.", es:"Lentes antiguas.", fr:"Lentilles anciennes.", de:"Alte Linsen." },
    "Modern rigor.": { he:"קפדנות מודרנית.", ar:"دقّةٌ حديثة.", ru:"Современная строгость.", es:"Rigor moderno.", fr:"Rigueur moderne.", de:"Moderne Strenge." },
    "Every recommendation traces back to peer-reviewed evidence. Traditions are offered as educational frameworks for reflection — never as medical claims — and labeled as such throughout.": { he:"כל המלצה ניתנת לעקיבה לראיות שעברו ביקורת עמיתים. המסורות מוצעות כמסגרות חינוכיות להרהור — לעולם לא כטענות רפואיות — ומסומנות ככאלה לכל אורך הדרך.", ar:"كل توصية تعود إلى أدلّةٍ محكَّمة. وتُقدَّم التقاليد كأُطرٍ تعليميةٍ للتأمّل — لا كادّعاءاتٍ طبية — وتُوسم كذلك في كل مكان.", ru:"Каждая рекомендация восходит к рецензируемым доказательствам. Традиции предлагаются как образовательные рамки для размышления — никогда как медицинские утверждения — и везде помечены соответствующе.", es:"Cada recomendación se remonta a evidencia revisada por pares. Las tradiciones se ofrecen como marcos educativos para reflexionar, nunca como afirmaciones médicas, y se etiquetan así en todo momento.", fr:"Chaque recommandation remonte à des preuves évaluées par les pairs. Les traditions sont proposées comme cadres éducatifs de réflexion — jamais comme allégations médicales — et signalées comme telles partout.", de:"Jede Empfehlung geht auf begutachtete Evidenz zurück. Traditionen werden als erzieherische Reflexionsrahmen angeboten — nie als medizinische Aussagen — und überall so gekennzeichnet." },
    "Studies in the evidence base": { he:"מחקרים בבסיס הראיות", ar:"دراسات في قاعدة الأدلّة", ru:"Исследований в доказательной базе", es:"Estudios en la base de evidencia", fr:"Études dans la base de preuves", de:"Studien in der Evidenzbasis" },
    "Weighted scoring model": { he:"מודל ניקוד משוקלל", ar:"نموذج تسجيل مرجّح", ru:"Взвешенная модель оценки", es:"Modelo de puntuación ponderada", fr:"Modèle de score pondéré", de:"Gewichtetes Bewertungsmodell" },
    "Advisory board": { he:"מועצה מייעצת", ar:"المجلس الاستشاري", ru:"Консультативный совет", es:"Consejo asesor", fr:"Conseil consultatif", de:"Beirat" },
    "Metabolic medicine": { he:"רפואה מטבולית", ar:"طب الأيض", ru:"Метаболическая медицина", es:"Medicina metabólica", fr:"Médecine métabolique", de:"Stoffwechselmedizin" },
    "Sleep & circadian science": { he:"מדע השינה והמקצב הצירקדי", ar:"علم النوم والإيقاع اليومي", ru:"Наука сна и циркадных ритмов", es:"Ciencia del sueño y circadiana", fr:"Science du sommeil et circadienne", de:"Schlaf- & zirkadiane Wissenschaft" },
    "Traditional medicine ethics": { he:"אתיקה של רפואה מסורתית", ar:"أخلاقيات الطب التقليدي", ru:"Этика традиционной медицины", es:"Ética de la medicina tradicional", fr:"Éthique des médecines traditionnelles", de:"Ethik traditioneller Medizin" },

